import{c as s,Q as n,j as e,m as t}from"./chunks/framework.BPKcPtvA.js";const d=JSON.parse('{"title":"@muhaven/mcp — first chat","description":"A walk-through from \\"show my portfolio\\" to a signed buy.","frontmatter":{"title":"@muhaven/mcp — first chat","description":"A walk-through from \\"show my portfolio\\" to a signed buy."},"headers":[],"relativePath":"mcp/first-chat.md","filePath":"mcp/first-chat.md","lastUpdated":1778983454000}'),o={name:"mcp/first-chat.md"};function p(l,a,i,u,r,c){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="your-first-chat" tabindex="-1">Your first chat <a class="header-anchor" href="#your-first-chat" aria-label="Permalink to &quot;Your first chat&quot;">​</a></h1><p>Assuming you&#39;ve completed <a href="/mcp/install">Install</a> and <code>muhaven-broker doctor</code> shows a valid JWT, you&#39;re ready to ask your LLM about MuHaven. The walkthrough below uses Claude Code; the others are identical except for how the tool result renders.</p><h2 id="_1-a-read-only-question" tabindex="-1">1. A read-only question <a class="header-anchor" href="#_1-a-read-only-question" aria-label="Permalink to &quot;1. A read-only question&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; What does my muhaven portfolio look like?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I&#39;ll check your MuHaven portfolio.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] muhaven.read.portfolio()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;positions&quot;: [</span></span>
<span class="line"><span>    { &quot;token&quot;: &quot;RWA1&quot;, &quot;asset_class&quot;: &quot;treasury&quot;, &quot;encrypted&quot;: true },</span></span>
<span class="line"><span>    { &quot;token&quot;: &quot;RWA2&quot;,  &quot;asset_class&quot;: &quot;gold&quot;,     &quot;encrypted&quot;: true }</span></span>
<span class="line"><span>  ],</span></span>
<span class="line"><span>  &quot;total_tokens&quot;: 2,</span></span>
<span class="line"><span>  &quot;last_synced&quot;: &quot;2026-05-16T10:32:14Z&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You hold 2 RWA tokens — RWA1 (treasury) and RWA2 (gold).</span></span>
<span class="line"><span>The actual balances are FHE-encrypted on-chain; if you want the</span></span>
<span class="line"><span>cleartext amounts, run \`muhaven.read.portfolio\` from your</span></span>
<span class="line"><span>dashboard at muhaven.app where you can decrypt locally with your</span></span>
<span class="line"><span>permit.</span></span></code></pre></div><p><strong>What just happened:</strong></p><ol><li>Claude saw your message + the MCP tool catalog and decided <code>muhaven.read.portfolio</code> was the right call.</li><li>The MCP server forwarded the call to the MuHaven backend with your JWT.</li><li>The backend returned the <strong>aggregate</strong> — token list + asset class + the boolean <code>encrypted: true</code>.</li><li><strong>No encrypted handle, no cleartext amount.</strong> The privacy invariant holds across the LLM context.</li></ol><h2 id="_2-a-yield-query" tabindex="-1">2. A yield query <a class="header-anchor" href="#_2-a-yield-query" aria-label="Permalink to &quot;2. A yield query&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; How much yield did my RWA2 earn last quarter?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] muhaven.read.yields({&quot;token&quot;:&quot;RWA2&quot;,&quot;since&quot;:&quot;2026-02-01T00:00:00Z&quot;})</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;token&quot;: &quot;RWA2&quot;,</span></span>
<span class="line"><span>  &quot;epochs&quot;: [</span></span>
<span class="line"><span>    { &quot;id&quot;: 4, &quot;distributed_at&quot;: &quot;2026-02-15T14:00:00Z&quot;, &quot;per_share_usd6&quot;: 1200 },</span></span>
<span class="line"><span>    { &quot;id&quot;: 5, &quot;distributed_at&quot;: &quot;2026-03-15T14:00:00Z&quot;, &quot;per_share_usd6&quot;: 1180 },</span></span>
<span class="line"><span>    { &quot;id&quot;: 6, &quot;distributed_at&quot;: &quot;2026-04-15T14:00:00Z&quot;, &quot;per_share_usd6&quot;: 1340 },</span></span>
<span class="line"><span>    { &quot;id&quot;: 7, &quot;distributed_at&quot;: &quot;2026-05-15T14:00:00Z&quot;, &quot;per_share_usd6&quot;: 1290 }</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>RWA2 paid yield over the last quarter:</span></span>
<span class="line"><span>- Feb epoch: $0.0012 / share</span></span>
<span class="line"><span>- Mar epoch: $0.00118 / share</span></span>
<span class="line"><span>- Apr epoch: $0.00134 / share</span></span>
<span class="line"><span>- May epoch: $0.00129 / share</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Annualized, that&#39;s roughly 1.5% yield. Want me to claim any</span></span>
<span class="line"><span>unclaimed amounts? I can call muhaven.position.claim with the</span></span>
<span class="line"><span>epoch IDs.</span></span></code></pre></div><h2 id="_3-a-propose-only-buy" tabindex="-1">3. A propose-only buy <a class="header-anchor" href="#_3-a-propose-only-buy" aria-label="Permalink to &quot;3. A propose-only buy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Buy 100 mhUSDC of RWA1.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] muhaven.position.buy({&quot;token&quot;:&quot;RWA1&quot;,&quot;amountUsd6&quot;:100000000})</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;envelope&quot;: {</span></span>
<span class="line"><span>    &quot;to&quot;: &quot;0x4f...&quot;,</span></span>
<span class="line"><span>    &quot;data&quot;: &quot;0x9a3b...&quot;,</span></span>
<span class="line"><span>    &quot;value&quot;: &quot;0x0&quot;</span></span>
<span class="line"><span>  },</span></span>
<span class="line"><span>  &quot;broker_signature&quot;: &quot;0xabc...&quot;,</span></span>
<span class="line"><span>  &quot;tier_check&quot;: &quot;ok&quot;,</span></span>
<span class="line"><span>  &quot;audit_id&quot;: &quot;agt_01HMTV...&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>I&#39;ve prepared a buy of 100 mhUSDC of RWA1. I have NOT submitted</span></span>
<span class="line"><span>it — MCP propose tools never auto-submit. Here&#39;s what you do:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Open https://muhaven.app/agent</span></span>
<span class="line"><span>2. You&#39;ll see this proposal pending in HavenBot</span></span>
<span class="line"><span>3. Confirm with your passkey</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Or use the dashboard&#39;s /policy page to inspect the envelope</span></span>
<span class="line"><span>manually.</span></span></code></pre></div><p><strong>What just happened:</strong></p><ol><li>Claude called <code>muhaven.position.buy</code> with a structured argument.</li><li>The backend ran the tool through the policy gate → cleared.</li><li>The broker signed a session-key authorization → returned both the unsigned UserOp envelope and the broker&#39;s session-key signature.</li><li><strong>The MCP server returned the envelope and the signature — it did NOT submit to a bundler.</strong> The host LLM is expected to surface the result to you for explicit confirmation through the dashboard or a host-presented review.</li></ol><p>This is the <strong>no-auto-submit invariant</strong>. A jailbroken LLM cannot drain your account because position / policy / issuer / governance tools never call any bundler. Final commit ceremony for value-moving actions always walks through the passkey-bound dashboard or a tier-aware confirmation surface.</p><h2 id="_4-pause" tabindex="-1">4. Pause <a class="header-anchor" href="#_4-pause" aria-label="Permalink to &quot;4. Pause&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Pause my agent.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] muhaven.policy.pause()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;result&quot;: &quot;paused&quot;,</span></span>
<span class="line"><span>  &quot;block&quot;: 8214321,</span></span>
<span class="line"><span>  &quot;block_time_ms&quot;: 240,</span></span>
<span class="line"><span>  &quot;audit_id&quot;: &quot;agt_01HMTV...&quot;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Your agent is paused. The on-chain session-key validator was</span></span>
<span class="line"><span>uninstalled in block 8214321. Subsequent propose calls</span></span>
<span class="line"><span>will return 423 PAUSED until you resume from the dashboard.</span></span></code></pre></div><p>Pause is the <strong>one</strong> state-mutating tool that always submits (because the kill-switch should be one-shot). It&#39;s idempotent and always allowed regardless of tier.</p><p>To resume:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; Resume my agent.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] You&#39;ll need to do that from the dashboard at</span></span>
<span class="line"><span>  https://muhaven.app/agent — resume requires a fresh passkey</span></span>
<span class="line"><span>  signature to install a new session-key validator. MCP can&#39;t</span></span>
<span class="line"><span>  drive the WebAuthn ceremony from here.</span></span></code></pre></div><p>The resume path involves a WebAuthn passkey ceremony that the MCP server can&#39;t drive (no DOM, no browser). Resume on the dashboard, then come back to MCP.</p><h2 id="what-you-can-t-do-via-mcp" tabindex="-1">What you can&#39;t do via MCP <a class="header-anchor" href="#what-you-can-t-do-via-mcp" aria-label="Permalink to &quot;What you can&#39;t do via MCP&quot;">​</a></h2><ul><li><strong>Decrypt encrypted handles.</strong> MCP returns aggregates; cleartext decrypt requires the dashboard <code>decryptForView</code> path because the permit needs your browser-side cofhe client.</li><li><strong>Resume after pause.</strong> The WebAuthn ceremony is dashboard-only.</li><li><strong>First-time onboarding.</strong> The <code>/agent/onboarding</code> wizard is dashboard-only. MCP assumes you already have a MuHaven wallet; if you don&#39;t, sign up on the dashboard first.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/mcp/playbook">Playbook — scenarios</a> — multi-MCP workflows, scheduled checks, cross-tool prompts.</li><li><a href="/mcp/tools">Tool catalog</a> — the full schema for every tool.</li><li><a href="/mcp/read-only-mode">Read-only mode</a> — restrict your MCP install to the 8 read tools.</li><li><a href="/mcp/troubleshooting">Troubleshooting</a> — auth, transport, lifecycle issues.</li></ul>`,23)])])}const q=s(o,[["render",p]]);export{d as __pageData,q as default};
